// Fungsi untuk mengubah kode warna Hexadesimal menjadi format RGB
function hexToRgb(e) {
    // Pola regex untuk mendeteksi warna hex versi pendek (contoh: #FFF)
    var a = /^#?([a-f\d])([a-f\d])([a-f\d])$/i;
    // Mengubah hex pendek menjadi hex panjang (contoh: #FFF menjadi #FFFFFF)
    e = e.replace(a, function(e, a, t, i) {
        return a + a + t + t + i + i; // Menggandakan setiap karakter
    });
    // Pola regex untuk mengekstrak 3 pasang nilai dari hex panjang
    var t = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(e);
    // Jika valid, kembalikan objek berisi nilai Red, Green, Blue dalam format desimal. Jika tidak, kembalikan null.
    return t ? {
        r: parseInt(t[1], 16), // Konversi string hexadesimal R ke desimal
        g: parseInt(t[2], 16), // Konversi string hexadesimal G ke desimal
        b: parseInt(t[3], 16)  // Konversi string hexadesimal B ke desimal
    } : null;
}

// Fungsi untuk membatasi sebuah nilai agar tidak kurang dari batas minimum (a) dan tidak lebih dari batas maksimum (t)
function clamp(e, a, t) {
    return Math.min(Math.max(e, a), t); // Menggunakan fungsi bawaan Math JS untuk memotong nilai yang kelewatan
}

// Fungsi untuk memeriksa apakah suatu elemen (e) ada di dalam sebuah array (a)
function isInArray(e, a) {
    return a.indexOf(e) > -1; // Mengembalikan true jika index ditemukan (lebih dari -1)
}

