/* =========================================================================
   SEGMENT 13: INISIALISASI (PENGATURAN MILIK BOS DAUS)
   Fungsi: Menjalankan mesin particlesJS di ID 'particles-js' dengan spesifikasi
========================================================================= */
particlesJS('particles-js', {
    particles: {
        number: {
            value: 100, // Menghasilkan tepat 100 butir salju putih beterbangan
            density: {
                enable: true, // Disebar pakai sistem kepadatan area
                value_area: 800 // Tiap luas lahan 800px akan ada sebaran rata 100 butir
            }
        },
        color: {
            value: '#ffffff' // Pewarna tubuh debu dituang full putih salju (#ffffff)
        },
        shape: {
            type: 'circle', // Wajahnya dipahat berbentuk bundar suci
            stroke: {
                width: 0, // Telanjang bulat tanpa coretan kawat pagar hitam mengitari tubuhnya
                color: '#000000'
            },
            polygon: {
                nb_sides: 5 // Cadangan abaikan jika dia bukan poligon
            },
            image: {
                src: 'img/github.svg', // Cadangan gambar logo github jika dia tipe gambar
                width: 100, height: 100
            }
        },
        opacity: {
            value: 0.5, // Selimut kebeningan debunya tembus pandang 50% menyatu alam
            random: true, // Beberapa disebar redup menyelinap, beberapa terang benderang menusuk
            anim: {
                enable: true, // Bernapas kelap kelip menyala berkedip pudar!
                speed: 1, // Ritme kedipan sangat lembut syahdu (1)
                opacity_min: 0.1, // Seredup-redupnya gak akan pudar abis total, mentok sisa 10% kedipan
                sync: false // Irama kedip diacak gak berbaris sama serentak kayak bebek!
            }
        },
        size: {
            value: 3, // Diameternya dikebiri super imut unyu mikro seukuran kutu beras 3px
            random: true, // Disilang acak, ada yg segede jerawat ada yg sekecil debu upil
            anim: {
                enable: true, // Ngembang ngempis hidup denyut pembuluh jantung nadi
                speed: 2, // Laju bengkaknya kenceng asik ritme 2
                size_min: 0.1, // Kisut menyusut mentok menderita batas wujud debu 0.1px 
                sync: false // Menyusut dan memuai acak ngawur sesuka hati gak keroyokan!
            }
        },
        line_linked: {
            enable: true, // JRENG! Tali jemuran data spasial antar bintang bersinar menenun layar 
            distance: 150, // Lemparan tali tambang maksimal menjangkau antar dua pulau sejauh 150px
            color: '#ffffff', // Serat optik ditenun cat putih pekat
            opacity: 0.4, // Cahaya fiber optik sedikit dilunturkan 40% agar tulisan Bos Daus tetap kontras
            width: 1 // Benang sutra dirajut setipis pedang seukuran 1 pixel saja!
        },
        move: {
            enable: true, // Kipas angin dewa dinyalakan.. WHUSSSH Debunya beterbangan merantau!!
            speed: 2, // Angin sepoi-sepoi nyetir kecepatan syahdu santai damai ritme 2
            direction: 'none', // Terbang tanpa arah kompas, bebas bagaikan burung hantu merdeka
            random: false, // Pergerakan meliuk elegan, tak sempoyongan pemabuk (false)
            straight: false, // Melayang belok berombak, tidak kaku mati macam busur panah lurus (false)
            out_mode: 'out', // Bebas menembus dinding batas horizon layar keluar bumi
            bounce: false, // Haram memantul balik dari dinding pinggir
            attract: {
                enable: false, // Tarikan pelet magnet saling bucin dimatikan
                rotateX: 600, rotateY: 1200
            }
        }
    },
    interactivity: {
        detect_on: 'canvas', // Mengikat radar satelit penguntit presisi di leher kanvas
        events: {
            onhover: {
                enable: true, // Radar nyala membaca sinyal udara kursor mouse jari bengkak user!
                mode: 'repulse' // BUM! Jari menolak menjauhkan memporak-porandakan kawanan debu yang melintas di sekitar!
            },
            onclick: {
                enable: true, // Pelatuk senjata ditekan (Mouse nge-Klik!)
                mode: 'push' // DORAEMON! Menyemburkan dan menjatuhkan kutukan debu partikel tambahan bertambah ramai ke muka layar!
            },
            resize: true // Jika HP Bos Daus dimiringin Lanskap.. susunan tata letak rasi hancur lalu disatukan balik menyesuaikan lebar rotasi HP secara adaptif jantan!
        },
        modes: {
            grab: {
                distance: 400, // Cengkraman jarak tali 400px (Diabaikan karena gak dipake di config)
                line_linked: { opacity: 1 }
            },
            bubble: {
                distance: 400, size: 40, duration: 2, opacity: 8, speed: 3 // Setelan Gelembung (Diabaikan)
            },
            repulse: {
                distance: 200, // Lingkaran hawa kekuatan dewa angin nolak debu sejauh gila 200 pixel!! Jangan sentuh aku! 
                duration: 0.4 // Waktu debu mental menabrak aspal pudar terpental 0.4 detik sangat brutal responsif
            },
            push: {
                particles_nb: 4 // Setiap senapan klik ditarik nembak, 4 mayat debu baru akan disemburkan tumpah melompat ke tengah padang belantara kordinat mouse lahir kembali menuntut balas
            },
            remove: {
                particles_nb: 2 // Cadangan (Diabaikan)
            }
        }
    },
    retina_detect: true // Mata dewa sihir Apple dinyalakan menajamkan pendar layar high DPI Super AMOLED agar tidak kotak kotak pecah buta 8 bit!
});